#include<bits/stdc++.h>
using namespace std;
const int N=200010;
vector<int> mp[N];
int rnk[N],top[N],siz[N],son[N],d[N],fa[N],dfn[N],val[N],dfncnt;
void dfs1(int x,int f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(auto i:mp[x])
    {
        int v=i;
        if(v!=f)
        {
            d[v]=d[x]+1;
            fa[v]=x;
            dfs1(v,x);
            siz[x]+=siz[v];
            if(son[x]==-1||siz[v]>siz[son[x]])
            {
                son[x]=v;
            }
        }
    }
}
void dfs2(int x,int t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(auto i:mp[x])
        {
            int v=i;
            if(v!=son[x]&&v!=fa[x])
            {
                dfs2(v,v);
            }
        }
    }
}
vector<int> v[N];
bool query(int x,int y,int z)
{
    int tx=top[x],ty=top[y];
    while(tx!=ty)
    {
        if(d[tx]<d[ty])
        {
            swap(x,y);
            swap(tx,ty);
        }
        auto it=lower_bound(v[z].begin(),v[z].end(),dfn[tx]);
        if(it!=v[z].end()&&(*it)<=dfn[x])
        {
            return true;
        }
        x=fa[tx];
        tx=top[x];
    }
    if(dfn[x]>dfn[y])
    {
        swap(x,y);
    }
    auto it=lower_bound(v[z].begin(),v[z].end(),dfn[x]);
    if(it!=v[z].end()&&(*it)<=dfn[y])
    {
        return true;
    }
    return false;
}
int main()
{
    int n;
    scanf("%d",&n);
    int q;
    scanf("%d",&q);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&val[i]);
    }
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs1(1);
    dfs2(1,1);
    for(int i=1;i<=dfncnt;i++)
    {
        v[val[rnk[i]]].push_back(i);
    }
    while(q--)
    {
        int a,b,c;
        scanf("%d%d%d",&a,&b,&c);
        int ans=0;
        ans=(int)query(a,b,c);
        printf("%d",ans);
    }
    return 0;
}
